#!/usr/bin/env node
/* reconcile-2026-06-05.mjs — one-shot reconciliation of the ledger INPUTS to the
 * verified reality (six independent investigations + harness gates, 2026-06-05).
 * Edits ONLY the 4 ledger inputs (progress.json + planning/*-decisions.json); the
 * ledger itself is regenerated by build-ledger.mjs afterward. Prints every change.
 * Re-runnable / idempotent. */
import { readFileSync, writeFileSync } from 'node:fs';
import { join, dirname, basename } from 'node:path';
import { fileURLToPath } from 'node:url';

const HERE = dirname(fileURLToPath(import.meta.url));
const PLANNING = join(HERE, 'planning');
const readJ = (p) => JSON.parse(readFileSync(p, 'utf8'));
const writeJ = (p, o) => writeFileSync(p, JSON.stringify(o, null, 2) + '\n');

const ledger = readJ(join(HERE, 'ledger.json'));
const byId = new Map(ledger.items.map((i) => [i.id, i]));
const hashOf = (id) => {
  const it = byId.get(id);
  if (!it) throw new Error(`reconcile: ledger has no item "${id}"`);
  return it.hunkHash;
};
const DATE = '2026-06-05';
const log = [];

// ---------------------------------------------------------------------------
// 1. progress.json — record APPLIED for the harness-verified work
// ---------------------------------------------------------------------------
const PROG = join(HERE, 'progress.json');
const prog = readJ(PROG);
prog.items = prog.items ?? {};
function setApplied(id, note) {
  prog.items[id] = {
    state: 'APPLIED',
    hunkHash: hashOf(id),
    attempts: (prog.items[id]?.attempts ?? 0),
    verifierNotes: [note],
    escalation: null,
  };
  log.push(`progress APPLIED  ${id}`);
}
setApplied('mos3#recon/wholeClass',
  `VERIFIED ${DATE}: harness mos3-gate.dts (Release.x64 DLL) firstDivergence null across all 8 classes; 147/147 steps, 185/185 cells. Class built mosfet3.ts, registered register-all.ts:455-456, TSTALLOC ≡ mos3set.c:234-255.`);
setApplied('jfet2#recon/wholeClass',
  `VERIFIED ${DATE}: harness jfet2-gate.dts (Release.x64 DLL) firstDivergence null across all 8 classes; 107/107 steps, identical iteration profile. Class built jfet2.ts (Parker-Skellern), registered register-all.ts:461-462; FIX-015 typeids present.`);
setApplied('mes#recon/wholeClass',
  `VERIFIED ${DATE}: harness mes-gate.dts (Release.x64 DLL) firstDivergence null across all 8 classes; 107/107 steps, identical iteration profile. Class built mesfet.ts (Statz), registered register-all.ts:459-460; FIX-015 typeids present.`);
setApplied('analysis#recon/opTran',
  `VERIFIED ${DATE}: gate #4 PASS — harness inductor-singular fixture (v1 1 0 dc3 / v2 2 0 dc5 / l1 1 2 1m) with optran enabled → firstDivergence null all 8 classes; L1:branch=-1.9999999999979999e-7 A bit-identical both sides. dynamicGmin terminal clean solve (dc-operating-point.ts:805-808 ≡ cktop.c dynamic_gmin) falls to OPtran exactly as ngspice. ESC-025/"FIX-006" overturned: no NIconvTest change needed (ngspice has none). optran-fallback-parity + optran-fallback tests 7/7.`);
setApplied('analysis/cktop.c#h001',
  `VERIFIED ${DATE}: unblocked by analysis#recon/opTran APPLIED. CKTop OPtran fall-through at dc-operating-point.ts:490-515 ≡ cktop.c:101-108.`);
writeJ(PROG, prog);

// ---------------------------------------------------------------------------
// 2. parser-decisions.json — NC the deck/model-card readers; delete dead ddtState
// ---------------------------------------------------------------------------
const PARSER = join(PLANNING, 'parser-decisions.json');
const parser = readJ(PARSER);
parser.items = parser.items ?? {};
parser.reconstruction = parser.reconstruction ?? {};

// Keep-set: the only genuinely-PORT parser hunks (blocked by the two real recons).
const PARSER_KEEP = new Set([
  'parser/ptfuncs.c#h005', 'parser/ptfuncs.c#h006', 'parser/inpptree.c#h010', 'parser/inpeval.c#h005', // numericalDeltas PORT
  'parser/inppas2.c#h001', 'parser/inppas2.c#h002', 'parser/inppas2.c#h003', 'parser/inpsymt.c#h001', // nodeAllocOrder
]);
const PARSER_NC_RATIONALE =
  'SPICE-deck text-parser / model-card reader frontend (INP2x device-card readers, INPdomodel/INPgetMod/INPgetTok/INPmakeMod model-card parser, B-source bison grammar). digiTS builds circuits from a structured CircuitSpec graph (.dig/.dts/JSON), not an ngspice text deck — these readers have no runtime counterpart. Verified ABSENT; architectural divergence ruled by user ' + DATE + '.';

// Every PENDING parser-doc hunk that is NOT in the keep-set -> NO-COUNTERPART.
let parserNc = 0;
for (const it of ledger.items) {
  if (it.kind !== 'hunk') continue;
  if (basename(it.diffDoc ?? '', '.md') !== 'parser') continue;
  if (it.state !== 'PENDING') continue;
  if (PARSER_KEEP.has(it.id)) continue;
  if (it.id === 'parser/ptfuncs.c#h007') continue; // ddt — own rationale below
  if (prog.items[it.id]) { log.push(`WARN parser NC skipped (has progress entry): ${it.id}`); continue; }
  parser.items[it.id] = { ...(parser.items[it.id] ?? {}), state: 'NO-COUNTERPART', tsFunction: null, rationale: PARSER_NC_RATIONALE };
  parserNc++;
}
// PTddt: the dead-recon hunk.
parser.items['parser/ptfuncs.c#h007'] = {
  ...(parser.items['parser/ptfuncs.c#h007'] ?? {}),
  state: 'NO-COUNTERPART', tsFunction: null,
  rationale: 'PTddt transient time-derivative (ptfuncs.c:412-466, adds PTddt to the PTnint tail) — needs CKTtime/MODETRAN history + per-instance ddt state the AST evaluator lacks; RULED OUT per expr-engine-numerical-deltas.md:421-425,552 (RATIFIED 2026-06-03). NO-COUNTERPART (user-ruled ' + DATE + ').',
};
log.push('parser NC  parser/ptfuncs.c#h007 (PTddt)');
log.push(`parser NC  ${parserNc} deck/model-card reader hunks`);
// Delete the stale duplicate recon (its spec never existed; numericalDeltas already dispositions its hunk).
if (parser.reconstruction['expr-engine#recon/ddtState']) {
  delete parser.reconstruction['expr-engine#recon/ddtState'];
  log.push('parser DELETE recon expr-engine#recon/ddtState (specExists:false; duplicate of numericalDeltas disposition)');
}
writeJ(PARSER, parser);

// ---------------------------------------------------------------------------
// 3. bjt-decisions.json — soaWarnings is read-only diagnostic -> delete recon + NC its hunk
// ---------------------------------------------------------------------------
const BJT = join(PLANNING, 'bjt-decisions.json');
const bjt = readJ(BJT);
bjt.items = bjt.items ?? {};
bjt.reconstruction = bjt.reconstruction ?? {};
if (bjt.reconstruction['bjt#recon/soaWarnings']) {
  delete bjt.reconstruction['bjt#recon/soaWarnings'];
  log.push('bjt DELETE recon bjt#recon/soaWarnings (specExists:false; read-only diagnostic, no numerical effect)');
}
bjt.items['bjt/bjtsoachk.c#h001'] = {
  ...(bjt.items['bjt/bjtsoachk.c#h001'] ?? {}),
  state: 'NO-COUNTERPART', tsFunction: null,
  rationale: 'BJTsoaCheck (DEVsoaCheck) is a read-only safe-operating-area diagnostic: bjtsoachk.c:44-138 only reads CKTrhsOld/CKTstate0 and emits soa_printf warnings — no matrix or RHS write (rth0 at :119 is a pdMax derating divisor, not a thermal node). SOA is not implemented in digiTS (no DEVsoaCheck/CKTsoaMaxWarns analogue), same disposition as bjtnoise/bjtdisto. The SOA limit model params ride the quasiSaturation recon declare-only. NO-COUNTERPART (user-ruled ' + DATE + ').',
};
log.push('bjt NC  bjt/bjtsoachk.c#h001');
writeJ(BJT, bjt);

// ---------------------------------------------------------------------------
console.log('=== reconcile-2026-06-05 applied ===');
for (const l of log) console.log('  ' + l);
console.log(`\nWrote: progress.json, parser-decisions.json, bjt-decisions.json`);
console.log('Next: node spec/v41-port/build-ledger.mjs && node spec/v41-port/build-ledger.mjs --check');
